"""
Additional edge-case tests for compute_largest_cc_size.
"""

import sys
from pathlib import Path

_tests_dir = Path(__file__).parent.parent / "public"
if str(_tests_dir) not in sys.path:
    sys.path.insert(0, str(_tests_dir))

from fixtures import make_test_result

TEST_POINTS = {
    "test_self_loop_node": 1,
    "test_large_disconnected": 1,
    "test_two_large_equal_components": 1,
    "test_string_node_keys": 1,
}


def test_self_loop_node(module):
    """A single node with a self-loop (edge to itself) should have CC size 1."""
    g = {0: {0}}
    result = module.compute_largest_cc_size(g)
    expected = 1
    return make_test_result(result == expected, expected, result)

test_self_loop_node.input_description = "g = {0: {0}}"


def test_large_disconnected(module):
    """100 isolated nodes: largest CC is 1."""
    g = {i: set() for i in range(100)}
    result = module.compute_largest_cc_size(g)
    expected = 1
    return make_test_result(result == expected, expected, result)

test_large_disconnected.input_description = "g = 100 isolated nodes"


def test_two_large_equal_components(module):
    """Two complete graphs of size 5, disconnected. Largest CC is 5."""
    g = {}
    for i in range(5):
        g[i] = set(range(5)) - {i}
    for i in range(10, 15):
        g[i] = set(range(10, 15)) - {i}
    result = module.compute_largest_cc_size(g)
    expected = 5
    return make_test_result(result == expected, expected, result)

test_two_large_equal_components.input_description = "g = K5 + K5 (disconnected)"


def test_string_node_keys(module):
    """Graph with string node keys."""
    g = {"a": {"b", "c"}, "b": {"a"}, "c": {"a"}, "d": set()}
    result = module.compute_largest_cc_size(g)
    expected = 3
    return make_test_result(result == expected, expected, result)

test_string_node_keys.input_description = "g = {a: {b, c}, b: {a}, c: {a}, d: {}}"
